Outreach Goal: {{outreach_goal}}

Business Profile (JSON):
{{business}}

Return ONLY a valid JSON object with this exact structure. No explanation, no markdown, no text outside the JSON:

{
  "is_qualified": true or false,
  "score": 0.0 to 1.0,
  "reasoning": "one sentence specific to this business",
  "icp_fit": {
    "industry_match": true or false,
    "size_match": true or false,
    "decision_maker_accessible": true or false
  }
}

Rules:
- is_qualified is true ONLY if the business clearly and unambiguously matches the outreach goal
- score reflects confidence: 0.9+ means very confident, 0.5-0.7 means uncertain
- reasoning must name the specific business and reference a concrete detail from the profile
- Do not qualify a business based on surface similarity alone; consider whether the outreach goal applies to their role, size, and independence

response.output:
{
  "is_qualified": true,
  "score": 0.92,
  "reasoning": "Karen Mills Family Law is a solo family law attorney practice in Chicago that clearly matches the target profile for practice management software designed for solo attorneys and small law firms.",
  "icp_fit": {
    "industry_match": true,
    "size_match": true,
    "decision_maker_accessible": true
  }
}

assert.value:
try {
  const r = JSON.parse(output);
  if (typeof r.is_qualified !== 'boolean') return { pass: false, score: 0, reason: 'is_qualified must be boolean' };
  if (typeof r.score !== 'number' || r.score < 0 || r.score > 1) return { pass: false, score: 0, reason: 'score must be number 0-1' };
  if (typeof r.reasoning !== 'string' || r.reasoning.length < 5) return { pass: false, score: 0, reason: 'reasoning must be non-empty string' };
  if (typeof r.icp_fit !== 'object' || r.icp_fit === null) return { pass: false, score: 0, reason: 'icp_fit must be object' };
  return { pass: true, score: 1, reason: 'schema valid' };
} catch (e) {
  return { pass: false, score: 0, reason: `JSON parse error: ${e.message}` };
}

try {
  const r = JSON.parse(output);
  const expected = context.vars.expected === 'true';
  const actual = r.is_qualified;
  if (actual === expected) {
    return { pass: true, score: 1, reason: `Correct: is_qualified=${actual}` };
  }
  return {
    pass: false,
    score: 0,
    reason: `Expected is_qualified=${expected}, got ${actual} (score=${r.score}). Reasoning: ${r.reasoning}`
  };
} catch (e) {
  return { pass: false, score: 0, reason: `Could not parse output: ${e.message}` };
}

